// // This module compares two 4-bit numbers and outputs whether they are equal, greater, or less. However, it incorrectly sets GT when A is less than B.
module magnitude_comparator(A, B, EQ, GT, LT);
input [3:0] A, B;
output EQ, GT, LT;

reg EQ, GT, LT;

always @(*) begin
    if (A == B) begin
        EQ = 1;
        GT = 0;
        LT = 0;
    end
    else if (A > B) begin
        EQ = 0;
        GT = 1;
        LT = 0;
    end
    else begin
        EQ = 0;
        GT = 0;
        LT = 1;
    end
end

endmodule
